pub fn nif_density(res: GraphRes) !f64 {
    const n = nodeCount(res);
    if (n <= 1) return 0.0;
    const possible_edges = @as(f64, @floatFromInt(n * (n - 1)));
    return @as(f64, @floatFromInt(edgeCount(res))) / possible_edges;
}

