        .soa => |g| try zog.flow.min_cut.globalMinCutF64(allocator, g),
        .hash_graph => |g| try zog.flow.min_cut.globalMinCutF64(allocator, g),
    };
    defer {
        allocator.free(result.group_a);
        allocator.free(result.group_b);
